#include <iostream>
#include <vector>
#include <unordered_set>
#include <algorithm>
using namespace std;
class Solution {
public:
    int solve(string s, int k, int n) {
        int res = 0;
        for (int i = 0; i < s.length(); i++)
        {
            int dist = 0;
            unordered_set<char> chars;
            for (int j = i; j < s.length(); j++)
            {
                if (s.at(j) == s.at(i))
                {
                    dist++;
                }
                chars.insert(s.at(j));
                if (chars.size() >= k)
                {
                    res = max(res, j - i + 1);
                }
            }
        }
        return res;
    }
};
int main() {
    Solution solution;
    string s;
    cin >> s;
    int k, n;
    cin >> k >> n;
    cout << solution.solve(s, k, n) << endl;
    return 0;
}
